mapper.select:
SELECT 
FROM woorido.users
WHERE social_provider = #{socialProvider}
  AND social_id = #{socialId}

mapper.update:
UPDATE woorido.users 
SET password_reset_token = #{resetToken}, 
    password_reset_expires = #{expiresAt}
WHERE id = #{id}

mapper.select:
SELECT total_score
FROM woorido.user_scores
WHERE user_id = #{userId}

mapper.insert:
INSERT INTO woorido.user_scores (
    id, user_id, total_score, created_at, updated_at
) VALUES (
    #{id}, #{userId}, #{totalScore}, SYSTIMESTAMP, SYSTIMESTAMP
)
